/* ===================== PYQ ENGINE ===================== */
const SqrtPyqState = { active:false, exam:'all', tier:'all', year:'all', yearCursor:0, qCursor:-1 };

function sqrtPyqAll(){
  const seen=new Set();
  return SQRT_PYQ_BANK.filter(q=>{
    if(!q||!q.id||seen.has(q.id)) return false;
    seen.add(q.id); return true;
  });
}

function matchSqrtPyqTier(q){
  if(!q.tier) return true;
  const selected=State.selectedExams;
  if(selected.length===0) return false;
  const tierMap={ '10thPass':'10th+','12thPass':'12th+','Graduate':'Grad+','Grad+':'Grad+' };
  const profileKey={ '10th+':'tenth_pass','12th+':'twelfth_pass','Grad+':'graduate' };
  const qGroup=profileKey[tierMap[q.tier]];
  if(!qGroup) return true;
  const ids=getExamIdsForGroup(qGroup);
  return ids.some(id=>selected.includes(id));
}

function sqrtPyqYears(){
  const exam=SqrtPyqState.exam;
  return [...new Set(sqrtPyqAll().filter(q=>{
    if(exam!=='all' && q.exam!==exam) return false;
    if(!matchSqrtPyqTier(q)) return false;
    return true;
  }).map(q=>q.year))].sort((a,b)=>b-a);
}

function sqrtPyqExams(){
  return [...new Set(sqrtPyqAll().filter(q=>{
    if(!matchSqrtPyqTier(q)) return false;
    return true;
  }).map(q=>q.exam))].sort();
}

function buildSqrtPyqQuestion(p){
  let ans, options;
  if(p.opts && Array.isArray(p.opts) && p.opts.length>=2){
    const optsWithAns = p.opts.includes(p.ans) ? p.opts : [p.ans, ...p.opts.slice(0,3)];
    options = shuffle(optsWithAns.slice(0,4).map(String));
    ans = options.indexOf(String(p.ans));
    if(ans===-1) ans=0;
  } else {
    const numAns=parseFloat(p.ans);
    if(!isNaN(numAns)){
      ans=numAns; let wrongs;
      if(numAns<=10) wrongs=[numAns+1,numAns+2,numAns-1];
      else if(numAns<=50) wrongs=[numAns+5,numAns-5,numAns+10];
      else wrongs=[numAns+10,numAns-10,numAns+20];
      wrongs=wrongs.filter(v=>v>0&&String(v)!==String(p.ans));
      options=shuffle([String(p.ans),...wrongs.slice(0,3).map(String)]);
      ans=options.indexOf(String(p.ans));
      if(ans===-1) ans=0;
    }
  }
  return {
    question:p.text,
    answer:ans,
    options,
    solution:p.solution,
    pyq:p,
    label:'PYQ · '+(p.subExam||p.exam)+' '+p.year,
    tier: p.tier,
    id: p.id
  };
}

function sqrtPyqNavigate(dir){
  const years=sqrtPyqYears();
  if(years.length===0) return null;
  function _filter(q){
    if(SqrtPyqState.exam!=='all' && q.exam!==SqrtPyqState.exam) return false;
    if(!matchSqrtPyqTier(q)) return false;
    return true;
  }
  const curYear=years[SqrtPyqState.yearCursor];
  const qs=sqrtPyqAll().filter(q=>_filter(q) && String(q.year)===String(curYear));
  if(dir>0){
    if(SqrtPyqState.qCursor===-1 || SqrtPyqState.qCursor+1>=qs.length){
      if(SqrtPyqState.qCursor!==-1){
        SqrtPyqState.yearCursor=(SqrtPyqState.yearCursor+1)%years.length;
      }
      SqrtPyqState.qCursor=0;
    }else{
      SqrtPyqState.qCursor++;
    }
  }else{
    if(SqrtPyqState.qCursor<=0){
      if(SqrtPyqState.qCursor!==-1){
        SqrtPyqState.yearCursor=(SqrtPyqState.yearCursor-1+years.length)%years.length;
      }
      const prevYear=years[SqrtPyqState.yearCursor];
      const prevQs=sqrtPyqAll().filter(q=>_filter(q) && String(q.year)===String(prevYear));
      SqrtPyqState.qCursor=prevQs.length-1;
    }else{
      SqrtPyqState.qCursor--;
    }
  }
  const newYear=years[SqrtPyqState.yearCursor];
  const newQs=sqrtPyqAll().filter(q=>_filter(q) && String(q.year)===String(newYear));
  if(SqrtPyqState.year!=='all' && String(SqrtPyqState.year)!==String(newYear)){
    SqrtPyqState.year=String(newYear);
    renderSqrtPyqYearChips();
  }
  return newQs[SqrtPyqState.qCursor]||null;
}

function renderSqrtPyqYearChips(){
  const wrap=$('#pyqYearChips');
  const years=sqrtPyqYears();
  wrap.innerHTML = `<span class="chip ${SqrtPyqState.year==='all'?'active':''}" data-year="all">All Years</span>` +
    years.map(y=>`<span class="chip ${String(SqrtPyqState.year)===String(y)?'active':''}" data-year="${y}">${y}</span>`).join('');
  wrap.querySelectorAll('.chip').forEach(c=>{
    c.addEventListener('click', ()=>{
      SqrtPyqState.year=c.dataset.year;
      const ylist=sqrtPyqYears();
      if(ylist.length>0){
        SqrtPyqState.yearCursor=ylist.findIndex(y=>String(y)===String(SqrtPyqState.year));
        if(SqrtPyqState.yearCursor<0) SqrtPyqState.yearCursor=0;
      }else SqrtPyqState.yearCursor=0;
      SqrtPyqState.qCursor=-1;
      renderSqrtPyqYearChips(); updateSqrtPyqStatus();
      if(SqrtPyqState.active) loadQuestion();
    });
  });
}

function renderSqrtPyqExamSelect(){
  const sel=$('#pyqExamSelect');
  const exams=sqrtPyqExams();
  const labels={cat:'CAT',cds:'CDS',dmrc_cra:'DMRC CRA',ibps_clerk:'IBPS Clerk',ibps_po:'IBPS PO',ibps_rrb:'IBPS RRB',ibps_so:'IBPS Spl. Officer',idbi_bank:'IDBI Bank Exec.',nda:'NDA',nicl_aao:'NICL AAO',rbi_assistant:'RBI Assistant',rbi_grade_b:'RBI Grade B',rrb_alp:'RRB ALP',rrb_group_d:'RRB Group D',rrb_ntpc:'RRB NTPC',sbi_jr_assoc:'SBI Jr. Associates',sbi_po:'SBI PO',ssc_cgl:'SSC CGL',ssc_chsl:'SSC CHSL',ssc_mts:'SSC MTS',state_psc:'State PSC',uiicl_asst:'UIICL Asst.',upsc_csat:'UPSC CSAT'};
  sel.innerHTML = `<option value="all" selected>📋 All Exams</option>` +
    exams.map(e=>`<option value="${e}" ${SqrtPyqState.exam===e?'selected':''}>${labels[e]||e}</option>`).join('');
}

function updateSqrtPyqStatus(){
  const years=sqrtPyqYears();
  const allCnt=sqrtPyqAll().filter(q=>matchSqrtPyqTier(q)).length;
  const labels={cat:'CAT',cds:'CDS',dmrc_cra:'DMRC CRA',ibps_clerk:'IBPS Clerk',ibps_po:'IBPS PO',ibps_rrb:'IBPS RRB',ibps_so:'IBPS Spl. Officer',idbi_bank:'IDBI Bank Exec.',nda:'NDA',nicl_aao:'NICL AAO',rbi_assistant:'RBI Assistant',rbi_grade_b:'RBI Grade B',rrb_alp:'RRB ALP',rrb_group_d:'RRB Group D',rrb_ntpc:'RRB NTPC',sbi_jr_assoc:'SBI Jr. Associates',sbi_po:'SBI PO',ssc_cgl:'SSC CGL',ssc_chsl:'SSC CHSL',ssc_mts:'SSC MTS',state_psc:'State PSC',uiicl_asst:'UIICL Asst.',upsc_csat:'UPSC CSAT'};
  if(SqrtPyqState.exam==='all'){
    $('#pyqStatus').innerHTML = `<span style="color:var(--muted);font-size:13px"><b style="color:var(--ink)">Selected Exams</b> · <b style="color:var(--ink)">${allCnt}</b> questions across <b style="color:var(--ink)">${years.length}</b> years</span>`;
  }else{
    const yrCnt=sqrtPyqAll().filter(q=>{
      if(q.exam!==SqrtPyqState.exam) return false;
      if(!matchSqrtPyqTier(q)) return false;
      return true;
    }).length;
    $('#pyqStatus').innerHTML = `<span style="color:var(--muted);font-size:13px"><b style="color:var(--ink)">${labels[SqrtPyqState.exam]||SqrtPyqState.exam}</b> · <b style="color:var(--ink)">${yrCnt}</b> questions across <b style="color:var(--ink)">${years.length}</b> years</span>`;
  }
}

function updateSqrtPyqModeUI(){
  const on=SqrtPyqState.active;
  $('#tabSetup').classList.toggle('hide', on);
  $('#tabPyq').classList.toggle('hide', !on);
  document.querySelectorAll('.capsule-tab').forEach(t=>t.classList.toggle('active', t.dataset.tab===(on?'pyq':'setup')));
  $('#typeTag').classList.toggle('hide', on);
  $('#similarBtn').classList.toggle('hide', on);
  $('#newBtn').classList.toggle('hide', on);
  $('#prevBtn').classList.toggle('hide', !on);
  $('#nextBtn').classList.toggle('hide', !on);
  $('#pyqStatus').classList.toggle('hide', !on);
}

